#include <stdio.h>
#include <math.h>
int main(){
    const double pi = acos(-1.0);
    double r;
    if(scanf("%lf", &r)!=1) return 0;
    double area = pi * r * r;
    double per = 2.0 * pi * r;
    printf("%.2f %.2f
", area, per);
    return 0;
}

